input.command:
Add-Type -AssemblyName System.Drawing
$path = "d:\Arumed-PrimaVision\arumed-frontend\src\assets\images\logo-rs-primavision.png"
$bmp = New-Object System.Drawing.Bitmap($path)
$w = $bmp.Width; $h = $bmp.Height
$minX=$w; $minY=$h; $maxX=0; $maxY=0
for ($y=0; $y -lt $h; $y++) {
  for ($x=0; $x -lt $w; $x++) {
    $a = $bmp.GetPixel($x,$y).A
    if ($a -gt 10) {
      if ($x -lt $minX){$minX=$x}; if ($x -gt $maxX){$maxX=$x}
      if ($y -lt $minY){$minY=$y}; if ($y -gt $maxY){$maxY=$y}
    }
  }
}
Write-Output "size=${w}x${h} bbox=($minX,$minY)-($maxX,$maxY) content=$(($maxX-$minX+1))x$(($maxY-$minY+1))"
$bmp.Dispose()

