/* ─── POPUP SUKSES LOGIN ─── */
.success-overlay {
  position: fixed;
  inset: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(10, 42, 77, 0.45);
  backdrop-filter: blur(3px);
}
.success-box {
  background: #fff;
  border-radius: 18px;
  padding: 2.25rem 2.75rem;
  text-align: center;
  box-shadow: 0 20px 60px rgba(10, 42, 77, 0.3);
  min-width: 280px;
}
.success-icon {
  width: 64px;
  height: 64px;
  margin: 0 auto 1rem;
  border-radius: 50%;
  background: var(--sb, #e8f3e9);
  color: #16a34a;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: success-pop 0.4s ease;
}
.success-icon svg { width: 34px; height: 34px; }
.success-title {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 22px;
  font-weight: 600;
  color: var(--td);
  margin-bottom: 4px;
}
.success-sub {
  font-size: 14px;
  color: var(--tu);
}
@keyframes success-pop {
  0%   { transform: scale(0.4); opacity: 0; }
  60%  { transform: scale(1.12); }
  100% { transform: scale(1); opacity: 1; }
}
/* Transition Vue untuk overlay */
.pop-enter-active { transition: opacity 0.25s ease; }
.pop-leave-active { transition: opacity 0.2s ease; }
.pop-enter-from, .pop-leave-to { opacity: 0; }
</style>

